    `,date:"15 fev",read:!1,starred:!0,folder:"inbox"},{id:4,from:"Colas \u{1F618}",fromEmail:"colas@valentinesmail.com",to:"filipa@valentinesmail.com",subject:"Convite para o Dia dos Namorados",body:`
